mapper.select:
SELECT s.id, s.staff_no AS staffNo, s.name, s.dept_id AS deptId, d.dept_name AS deptName, s.title, s.user_id AS userId, s.status FROM staff s LEFT JOIN dept d ON d.id = s.dept_id
AND s.dept_id = #{deptId} AND s.status = #{status}
ORDER BY s.id

mapper.update:
UPDATE staff
name = #{name}, dept_id = #{deptId}, title = #{title}, user_id = #{userId}, status = #{status},
WHERE id = #{id}
